        // Serialization: write sensor_id, convert temperatures to little-endian, write converted temps, convert pressure to little-endian, write converted pressure
        adaptor.serialise(sensor_id);

        for (auto& temp : temperatures) {
            float converted_temp = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.serialise(converted_temp);
        }

        double converted_pressure = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.serialise(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read sensor_id, read temperatures, convert each in-place from little-endian to native, read pressure, convert in-place from little-endian to native
        adaptor.deserialise(sensor_id);

        temperatures.clear();
        uint32_t temp_count = temperatures.capacity(); // Assuming we know the count from serialization context

        for (uint32_t i = 0; i < temp_count; ++i) {
            float temp_value;
            adaptor.deserialise(temp_value);
            hexi::endian::little_to_native_inplace(temp_value);
            temperatures.push_back(temp_value);
        }

        double pressure_value;
        adaptor.deserialise(pressure_value);
        hexi::endian::little_to_native_inplace(pressure_value);
        pressure = pressure_value;
    }
};

